/// <summary>
/// Implements the Controller part of the MVC pattern for report rendering and running.
/// </summary>
/// <remarks>
/// We are extended this class fromt he srsreportruncontroller for adding the some more customization fields.
/// This is a framework class. Customizing this class may cause problems with future upgrades to the software.
/// </remarks>
class ETGCreditNoteController extends SrsReportRunController
{
}

Method.Source:
Protected void preRunModifyContract()
{
    LedgerJournalTable      ledgerJournalTable;
    LedgerJournalTrans      ledgerJournalTrans;
    str                     reportnameLocal;
    ETGCreditNoteContract   contract;
    FormRun                 callerForm;
    contract = this.parmReportContract().parmRdpContract() as ETGCreditNoteContract;
    if(this.parmArgs().menuItemName() == menuitemOutputStr(ETGCreditNoteReport))
    {
        callerForm = args.caller();
        if(callerForm.dataSource().name() == formDataSourceStr(LedgerJournalTable,LedgerJournalTable))
        {
            ledgerJournalTable             = args.record();
        }
        if(callerForm.dataSource().name() == formDataSourceStr(LedgerJournalTransDaily,LedgerJournalTrans))
        {
            ledgerJournalTrans             = args.record();
            ledgerJournalTable             = ledgerJournalTrans.ledgerJournalTable();
        }
        contract.parmJournalNum(ledgerJournalTable.JournalNum);
        contract.parmReportName(menuitemOutputStr(ETGCreditNoteReport));

        if (curext() == 'E003')
        {
            // E003 uses specialized E003 design
            reportnameLocal = ssrsReportStr(ETGCreditNoteReport, ETGCreditNoteE003);
        }
        else if (curext() == 'E016')
        {
            // E016 uses specialized E016 design
            reportnameLocal = ssrsReportStr(ETGCreditNoteReport, ETGCreditNoteE016);
        }
        else if (curExt() == "S004")
        {
            // S004 uses specialized S004 design
            reportnameLocal = ssrsReportStr(ETGCreditNoteReport, ETGCreditNoteS004);
        }
        else if (curExt() == "C003")
        {
            // C003 uses specialized C003 design
            reportnameLocal = ssrsReportStr(ETGCreditNoteReport, ETGCreditNoteC003);
        }
        else
        {
            // All other entities use default design
            reportnameLocal = ssrsReportStr(ETGCreditNoteReport, Report);
        }





    }
    else if(this.parmArgs().menuItemName() == menuitemOutputStr(ETGDebitNoteReport))
    {
        callerForm = args.caller();
        if(callerForm.dataSource().name() == formDataSourceStr(LedgerJournalTable,LedgerJournalTable))
        {
            ledgerJournalTable = args.record();
        }
        if(callerForm.dataSource().name() == formDataSourceStr(LedgerJournalTransDaily,LedgerJournalTrans))
        {
            ledgerJournalTrans = args.record();
            ledgerJournalTable  = ledgerJournalTrans.ledgerJournalTable();
        }
        contract.parmJournalNum(ledgerJournalTable.JournalNum);
        contract.parmReportName(menuitemOutputStr(ETGDebitNoteReport));

        if (curExt() == "E003")
        {
            // E003 uses specialized E003 design
            reportnameLocal = ssrsReportStr(ETGCreditNoteReport, ETGDebitNoteE003);
        }
        else if (curExt() == "E016")
        {
            // E016 uses specialized E016 design
            reportnameLocal = ssrsReportStr(ETGCreditNoteReport, ETGDebitNoteE016);
        }
        else if (curExt() == "S004")
        {
            // S004 uses specialized S004 design
            reportnameLocal = ssrsReportStr(ETGCreditNoteReport, ETGDebitNoteS004);
        }
        else if (curExt() == "C003")
        {
            // C003 uses specialized C003 design
            reportnameLocal = ssrsReportStr(ETGCreditNoteReport, ETGDebitNoteC003);
        }
        else
        {
            // All other entities use default design
            reportnameLocal = ssrsReportStr(ETGCreditNoteReport, DebitReport);
        }


    }
    this.parmReportContract().parmReportName(reportnameLocal);
}

public static void main(args _args)
{
    ETGCreditNoteController controller = new ETGCreditNoteController();
    controller.parmReportName(ssrsReportStr(ETGCreditNoteReport,Report));
    controller.parmArgs(_args);
    controller.parmShowDialog(false);
    controller.startOperation();
}
